function candidate(name, value, settings) {
  const options = settings == null ? {} : settings;
  const encoder = options.encode == null ? encodeURIComponent : options.encode;

  if (typeof encoder !== "function") {
    throw new TypeError("option encode is invalid");
  }

  const tokenPattern = /^[!#$%&'*+\-.^_`|~0-9A-Za-z]+$/;
  if (typeof name !== "string" || !tokenPattern.test(name)) {
    throw new TypeError("cookie name is invalid");
  }

  const encoded = encoder(value);
  const text = String(encoded);
  const valuePattern = /^[\x21\x23-\x2B\x2D-\x3A\x3C-\x5B\x5D-\x7E]*$/;
  if (text !== "" && !valuePattern.test(text)) {
    throw new TypeError("cookie value is invalid");
  }

  let output = name + "=" + text;

  if (options.maxAge) {
    const seconds = Math.floor(Number(options.maxAge));
    if (!Number.isFinite(seconds)) {
      throw new TypeError("maxAge is invalid");
    }
    output += "; Max-Age=" + seconds;
  }

  if (options.domain) {
    const domain = String(options.domain);
    const domainPattern = /^(?:[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?\.)*[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?$/;
    if (!domainPattern.test(domain)) {
      throw new TypeError("domain is invalid");
    }
    output += "; Domain=" + domain;
  }

  if (options.path) {
    const path = String(options.path);
    if (!/^[\x20-\x3A\x3D-\x7E]*$/.test(path)) {
      throw new TypeError("path is invalid");
    }
    output += "; Path=" + path;
  }

  if (options.expires) {
    if (typeof options.expires.toUTCString !== "function") {
      throw new TypeError("expires is invalid");
    }
    output += "; Expires=" + options.expires.toUTCString();
  }

  if (options.httpOnly) {
    output += "; HttpOnly";
  }

  if (options.secure) {
    output += "; Secure";
  }

  if (options.sameSite) {
    const sameSite = options.sameSite === true ? "strict" : String(options.sameSite).toLowerCase();
    if (sameSite === "strict") {
      output += "; SameSite=Strict";
    } else if (sameSite === "lax") {
      output += "; SameSite=Lax";
    } else if (sameSite === "none") {
      output += "; SameSite=None";
    } else {
      throw new TypeError("sameSite is invalid");
    }
  }

  return output;
}
